import React from 'react';
import { BrowserRouter as Router, Route, Switch, Redirect } from 'react-router-dom';
import { AuthProvider } from './context/AuthContext';

// Main site components
import Header from './components/Header';
import Footer from './components/Footer';
import Preloader from './components/Preloader';

// Regular pages
import HomePage from './pages/HomePage';
import CoursesPage from './pages/CoursesPage';
import AboutPage from './pages/AboutPage';
import ContactPage from './pages/ContactPage';
import ApplyPage from './pages/ApplyPage';
import NewsPage from './pages/NewsPage';
import LoginPage from './pages/LoginPage';
import RegisterPage from './pages/RegisterPage';

// Admin pages
import AdminDashboard from './pages/admin/Dashboard';
import AdminApplications from './pages/admin/Applications';
import AdminContacts from './pages/admin/Contacts';
import AdminStudents from './pages/admin/Students';
import AdminCourses from './pages/admin/Courses';
import AdminSettings from './pages/admin/Settings';

// Student pages
import StudentDashboard from './pages/student/Dashboard';
import StudentProfile from './pages/student/Profile';
import StudentCourses from './pages/student/Courses';
import StudentAssignments from './pages/student/Assignments';

// Protected route component
import ProtectedRoute from './components/layout/ProtectedRoute';

function App() {
  return (
    <AuthProvider>
      <Router>
        <Switch>
          {/* Admin Routes - No Header/Footer */}
          <ProtectedRoute path="/admin/dashboard" component={AdminDashboard} allowedRoles={['admin']} />
          <ProtectedRoute path="/admin/applications" component={AdminApplications} allowedRoles={['admin']} />
          <ProtectedRoute path="/admin/contacts" component={AdminContacts} allowedRoles={['admin']} />
          <ProtectedRoute path="/admin/students" component={AdminStudents} allowedRoles={['admin']} />
          <ProtectedRoute path="/admin/courses" component={AdminCourses} allowedRoles={['admin']} />
          <ProtectedRoute path="/admin/settings" component={AdminSettings} allowedRoles={['admin']} />
          <Route path="/admin" exact>
            <Redirect to="/admin/dashboard" />
          </Route>

          {/* Student Routes - No Header/Footer */}
          <ProtectedRoute path="/student/dashboard" component={StudentDashboard} allowedRoles={['student']} />
          <ProtectedRoute path="/student/profile" component={StudentProfile} allowedRoles={['student']} />
          <ProtectedRoute path="/student/courses" component={StudentCourses} allowedRoles={['student']} />
          <ProtectedRoute path="/student/assignments" component={StudentAssignments} allowedRoles={['student']} />
          <Route path="/student" exact>
            <Redirect to="/student/dashboard" />
          </Route>

          {/* Auth Routes - No Header/Footer */}
          <Route path="/login" component={LoginPage} />
          <Route path="/register" component={RegisterPage} />

          {/* Regular Pages - With Header/Footer */}
          <Route path="/" exact>
            <Header />
            <HomePage />
            <Footer />
          </Route>
          <Route path="/courses">
            <Header />
            <CoursesPage />
            <Footer />
          </Route>
          <Route path="/about">
            <Header />
            <AboutPage />
            <Footer />
          </Route>
          <Route path="/contact">
            <Header />
            <ContactPage />
            <Footer />
          </Route>
          <Route path="/apply">
            <Header />
            <ApplyPage />
            <Footer />
          </Route>
          <Route path="/news">
            <Header />
            <NewsPage />
            <Footer />
          </Route>
        </Switch>
      </Router>
    </AuthProvider>
  );
}

export default App;
